+/// BSD `arc4random` — return a random 32-bit value.
+#[cfg_attr(not(debug_assertions), unsafe(no_mangle))]
+pub unsafe extern "C" fn arc4random() -> u32 {
+    let mut val: u32 = 0;
+    unsafe {
+        libc::syscall(
+            libc::SYS_getrandom,
+            &mut val as *mut u32 as *mut c_void,
+            4usize,
+            0,
+        );
+    }
+    val
+}
