+/// BSD `arc4random_buf` — fill buffer with random bytes.
+#[cfg_attr(not(debug_assertions), unsafe(no_mangle))]
+pub unsafe extern "C" fn arc4random_buf(buf: *mut c_void, nbytes: usize) {
+    unsafe {
